    ('BIOL-L 307', 'BIODIVERSITY', '7138', 'Closed', 'M Monday 1:00 PM–5:00 PM', 'HD TBA', 'Laura Mojonnier', 0, NULL, 'Laboratory', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Provides a strong framework and hands-on experience studying biodiversity. Course transitions between introductory materials considered in L111 and L112 and more advanced courses focused on specific groups of organisms (for example, vertebrate zoology). Includes field and lab components where local biodiversity is sampled and analyzed.', ARRAY['COLL (CASE) Sustainability Literacy credit'], NULL),
    ('BIOL-L 311', 'GENETICS', '1080', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'JH A100', 'Wayne Forrester', 4, 'Lecture', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Analysis of the mechanisms of inheritance, including developmental processes that lead to the construction of whole organisms and to the transmission to their offspring of specific genetic traits. Includes the principles of genetics and the analysis of mutations affecting development.', ARRAY[]::TEXT[], NULL),
