    ('BIOL-L 311', 'GENETICS', '7886', 'Closed', 'W Wednesday 10:25 AM–11:15 AM', 'JH A105', 'Wayne Forrester', 0, 'Discussion', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Analysis of the mechanisms of inheritance, including developmental processes that lead to the construction of whole organisms and to the transmission to their offspring of specific genetic traits. Includes the principles of genetics and the analysis of mutations affecting development.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 311', 'GENETICS', '35026', 'Closed', 'M Monday 3:10 PM–4:00 PM', 'BH 232', 'Wayne Forrester', 0, 'Discussion', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Analysis of the mechanisms of inheritance, including developmental processes that lead to the construction of whole organisms and to the transmission to their offspring of specific genetic traits. Includes the principles of genetics and the analysis of mutations affecting development.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 312', 'CELL BIOLOGY', '1081', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'JH 065', 'Sapna Mehta', 5, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Current views of the structure and function of cellular organelles and components, with emphasis on the flow of information through the cell, the metabolism that supports cellular functions and differences among different specialized cells. Current techniques will be stressed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-L 313', 'CELL BIOLOGY LABORATORY', '12220', 'Closed', 'Th Thursday 9:30 AM–12:30 PM', 'JH A104', 'Karen Whitworth', 0, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Laboratory topics include: microscopy and the visualization of cellular structures, genetic manipulation of cells, antibody-based diagnostic assays, and protein purification.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 313', 'CELL BIOLOGY LABORATORY', '12221', 'Closed', 'Th Thursday 1:00 PM–4:00 PM', 'JH A104', 'Karen Whitworth', 0, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Laboratory topics include: microscopy and the visualization of cellular structures, genetic manipulation of cells, antibody-based diagnostic assays, and protein purification.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 318', 'EVOLUTION', '1082', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'RH 100', 'Cris Ledon-Rettig', 1, NULL, 'Lecture', '3', 'RAWLES HALL', ARRAY[]::TEXT[], 'Provides a rigorous exploration of the theory of evolution - the conceptual core of biology. Topics include origins and history of life, the interplay of heredity and environment in shaping adaptations, molecular, behavioral and social evolution, patterns of speciation, extinction, and their consequences, methods for inferring evolutionary relationship among organism', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-L 319', 'GENETICS LABORATORY', '1083', 'Class Status', NULL, 'M Monday 12:45 PM–1:35 PM W Wednesday 7:00 PM–9:00 PM W Wednesday 7:00 PM–9:00 PM Regular Academic Session 8/25/2025–12/19/2025', 'JH A100 JH A100 JH A100', NULL, 'Lecture', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Experiments with plants, animals, bacteria, and viruses demonstrating fundamental genetic mechanisms.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 319', 'GENETICS LABORATORY', '1085', 'Class Status', 'W Wednesday 1:45 PM–4:20 PM', 'JH 015', 'Richard Holdeman', 2, 'Laboratory', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Experiments with plants, animals, bacteria, and viruses demonstrating fundamental genetic mechanisms.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 319', 'GENETICS LABORATORY', '1084', 'Closed', 'Tu Tuesday 1:45 PM–4:20 PM', 'JH 015', 'Richard Holdeman', 0, 'Laboratory', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Experiments with plants, animals, bacteria, and viruses demonstrating fundamental genetic mechanisms.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 322', 'WRITING WORKSHOP IN BIOLOGY', '3485', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'FA 004', 'Brian Winterman', 0, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'Development of scientific writing styles and techniques to help students learn about complex phenomena, sharpen thought processes used in evaluating complicated data, and develop skills essential for communicating intricate ideas and concepts. Research reports will be regularly reviewed by the instructor, and in the context of cooperative learning groups.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('BIOL-L 323', 'MOLECULAR BIOLOGY LABORATORY', '1087', 'Class Status', 'TuTh Tuesday, Thursday 1:10 PM–5:10 PM', 'JH 031', 'Stefan Surzycki', 3, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Manipulations and analysis of genes and genomes. Gene cloning and library screening. Gene amplification and disease diagnosis. Gene mapping and Southern blot analysis of complex genome structure.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 323', 'MOLECULAR BIOLOGY LABORATORY', '1086', 'Closed', 'MW Monday, Wednesday 1:10 PM–5:10 PM', 'JH 031', 'Stefan Surzycki', 0, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Manipulations and analysis of genes and genomes. Gene cloning and library screening. Gene amplification and disease diagnosis. Gene mapping and Southern blot analysis of complex genome structure.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 323', 'MOLECULAR BIOLOGY LABORATORY', '34052', 'Closed', 'MW Monday, Wednesday 1:10 PM–5:10 PM', 'JH 031', 'Stefan Surzycki', 0, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Manipulations and analysis of genes and genomes. Gene cloning and library screening. Gene amplification and disease diagnosis. Gene mapping and Southern blot analysis of complex genome structure.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 323', 'MOLECULAR BIOLOGY LABORATORY', '34053', 'Closed', 'TuTh Tuesday, Thursday 1:10 PM–5:10 PM', 'JH 031', 'Stefan Surzycki', 0, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Manipulations and analysis of genes and genomes. Gene cloning and library screening. Gene amplification and disease diagnosis. Gene mapping and Southern blot analysis of complex genome structure.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 326', 'BIODIVERSE-CITY: THE ART AND SCIENCE OF GREEN INFRASTRUCTURE', '7167', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'JH 065', 'Heather Reynolds', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'An interdisciplinary, place-based approach to understanding biological diversity and its relationship to flourishing human societies, and to developing associated skills and values (e.g. interdisciplinary thinking and action, stewardship).', ARRAY['COLL (CASE) Sustainability Literacy credit'], NULL),
    ('BIOL-L 331', 'INTRODUCTION TO HUMAN GENETICS', '1088', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'JH 440', 'Stefan Surzycki', 15, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Principles of human genetics are presented. The emphases are on new developments in the field afforded by present day techniques in molecular biology. Among the topics considered are: sex inheritance, molecular basis of genetic diseases, oncogensis, immune system structure.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 340', 'BIOLOGY OF SEXUAL DIVERSITY', '29822', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 130', 'Gerald Smith', 0, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Introduces biological processes underlying sex-related variation in anatomy, physiology, and behavior. Includes discussions of sexual differentiation in organisms ranging from yeast to human. Addresses functional (evolutionary/ecological) and mechanistic (developmental/physiological) explanations for sexual variation.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('BIOL-L 350', 'ENVIRONMENTAL BIOLOGY', '1089', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'JH 009', 'Laura Mojonnier', 4, 'Lecture', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Global ecology in relation to human needs; human population growth and impact; pollution; land use; and political and social aspects of environmental sciences.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
