    ('BIOL-L 410', 'TOPICAL ISSUES IN BIOLOGY', '10505', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 227', 'Adam Fudickar', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Topics not covered extensively in other courses. The topic will vary depending on the instructor and on student needs.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 410', 'TOPICAL ISSUES IN BIOLOGY', '10172', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'JH 248', 'Ellen Ketterson', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Topics not covered extensively in other courses. The topic will vary depending on the instructor and on student needs.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 417', 'DEVELOPMENTAL BIOLOGY AND STEM CELLS', '29679', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'JH A106', 'Andrew Zelhof', 11, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Analysis of the developmental processes that lead to the construction of whole organisms from single stem cells. Covers the molecular and genetic analysis of mutations and pathways that disrupt these processes and cause disease. Other topics include adult stem cells and their role in tissue regeneration.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 474', 'FIELD AND LABORATORY ECOLOGY', '1090', 'Class Status', 'W Wednesday 12:45 PM–5:10 PM', 'HD TBA', 'Tara Darcy', 1, NULL, 'Laboratory', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Introduction to research problems and techniques in the ecology of individuals, populations and ecosystems.', ARRAY['Class uses IU eTexts
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('BIOL-L 485', 'GENETICS, MODELS OF HUMAN DISEASE, AND CRITICAL ANALYSIS OF BIOLOGICAL RESEARCH', '8870', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 344', 'Brian Calvi, Peter Hollenhorst, Lachezar Nikolov', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores the development of genetic manipulations and techniques (e.g. epistasis to CRISPR/Cas9) to address fundamental questions of life. Students will critically read and discuss primary literature.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 500', 'INDEPENDENT STUDY', '1091', 'Class Status', NULL, NULL, 'Armin Moczek', 35, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('BIOL-L 501', 'INDEPENDENT STUDY FOR ROTATIONS', '1092', 'Class Status', NULL, NULL, 'Armin Moczek', 32, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'L501 is used for Biology students who are conducting Independent Study during lab rotations in the GCDB or EEB Graduate Programs. Each credit should correspond to 3-4 hours of formal coursework.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 523', 'CRITICAL ANALYSIS OF THE SCIENTIFIC LITERATURE', '10730', 'Class Status', 'F Friday 9:10 AM–10:00 AM', 'JH A106', 'Heather Hundley', 8, NULL, 'Lecture', '1.5', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Detailed analysis of current research papers in biology. Emphasis on experimental design, research methods, interpretation of results, and suitability of controls. Generally taken in the first semester of graduate residence. Topics may vary to suit specific fields (e.g. Molecular, Cellular, and Developmental Biology and Genetics, or Ecological and Evolutionary biology).', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 523', 'CRITICAL ANALYSIS OF THE SCIENTIFIC LITERATURE', '32055', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 142', 'Julia van Kessel', 14, NULL, 'Lecture', '1.5', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Detailed analysis of current research papers in biology. Emphasis on experimental design, research methods, interpretation of results, and suitability of controls. Generally taken in the first semester of graduate residence. Topics may vary to suit specific fields (e.g. Molecular, Cellular, and Developmental Biology and Genetics, or Ecological and Evolutionary biology).', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 570', 'SEMINAR IN ECOLOGY AND ENVIRONMENTAL BIOLOGY', '1093', 'Class Status', 'Tu Tuesday 11:10 AM–12:25 PM', 'LH 035', 'Spencer Hall, Jay Lennon', 22, NULL, 'Seminar', '1', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Presentations and discussions of current research in Evolution, Ecology, and Behavior.', ARRAY[]::TEXT[], NULL),
    ('BIOL-L 585', 'MOLECULAR GENETICS OF MODEL ORGANISMS', '4842', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 344', 'Brian Calvi, Peter Hollenhorst, Lachezar Nikolov', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This lecture and discussion course focuses on advanced concepts and techniques of genetics, molecular genetics, genomics and the use of model organisms. Sessions include in depth discussions of the primary scientific literature that describe the use of genetic model organisms for biomedical discovery.', ARRAY[]::TEXT[], NULL),
