    ('BIOL-M 316', 'MOLECULAR MICROBIOLOGY LABORATORY', '13455', 'Class Status', 'MW Monday, Wednesday 1:55 PM–4:25 PM', 'JH A012', 'Julia van Kessel', 11, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Laboratory of inquiry-based projects meant to build proficiency in aseptic technique, microbial cultivation, and molecular characterization of microbes.', ARRAY[]::TEXT[], NULL),
    ('BIOL-M 380', 'MICROBIOLOGY OF INFECTIOUS DISEASE', '5452', 'Closed', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WH 003', 'Megan Dunn', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'A guide to the complex subject of infectious disease. Builds on basic biological principles to examine different agents of disease, the major modes of transmission, interaction of pathogens with the host immune system, and the ecological factors facilitating or inhibiting the emergence of epidemic disease.', ARRAY[]::TEXT[], NULL),
    ('BIOL-M 430', 'VIROLOGY LECTURE', '29823', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'JH 009', 'Pranav Danthi', 8, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Viruses of plants, animals (including humans), and bacteria; emphasis on molecular biology of viral systems. Viruses and human disease such as cancer and AIDS; viruses and their evolution.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('BIOL-M 435', 'VIRAL-TISSUE-CULTURE LABORATORY', '29824', 'Class Status', 'TuTh Tuesday, Thursday 1:30 PM–4:30 PM', 'JH 022', 'Suchetana Mukhopadhyay', 1, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Laboratory will emphasize eukarytotic cell tissue culture and common virological assays used in research and clinical lab settings.', ARRAY[]::TEXT[], NULL),
    ('BIOL-M 440', 'MEDICAL MICROBIOLOGY LECTURES', '1095', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'JH 001', 'Malcolm Winkler', 3, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Covers microorganisms as agents of disease, host-parasite relationships, epidemiology, and chemotherapy.', ARRAY[]::TEXT[], NULL),
    ('BIOL-M 445', 'MED MICROBIOLOGY LABORATORY', '6605', 'Class Status', 'MW Monday, Wednesday 1:50 PM–4:50 PM', 'JH 022', 'Megan Dunn', 6, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('BIOL-M 480', 'MICROBIAL AND MOLECULAR GENETICS', '1096', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'JH A106', 'Dean Rowe-Magnus', 28, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Microbes have shaped human history and biological understanding in titanic ways. Course covers ground-breaking experiments that defined essential cellular processes (replication, transcription, translation) in all living organisms, possible origins of life on Earth, microorganism adaptation and pathogen evolution, and advances in medicine, biotechnology, and scientific challenges facing mankind.', ARRAY[]::TEXT[], NULL),
    ('BIOL-M 500', 'INTRODUCTION TO RESEARCH', '1097', 'Class Status', NULL, NULL, 'Armin Moczek', 14, NULL, 'Research', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('BIOL-M 550', 'MICROBIOLOGY', '5017', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'MO 007', 'Irene Newton', 4, NULL, 'Lecture', '3', 'MORRISON HALL', ARRAY[]::TEXT[], 'Application of fundamental principles to the study of microorganisms. Significance of microorganisms to humans and their environment. Critical evaluation of current microbiological literature.', ARRAY[]::TEXT[], NULL),
