    ('BIOL-P 451', 'INTEGRATIVE HUMAN PHYSIOLOGY', '3412', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'GA 1128', 'Whitney Schlegel', 6, 'Lecture', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intended for the junior or senior science major. Course in human physiology designed to introduce the senior undergraduate student to the function of the human body in health, disease, and extreme environments. Emphasizes how the different organ systems work to maintain homeostasis and how organ function is integrated. The content and key concepts are presented in order to provide students insight into the scientific process through problem-solving and exploration of resources. Utilizes experimental inquiry, case-based and problem-oriented methodology with students working in teams and an emphasis on clinical application. The laboratory component is incorporated into the structure of the course.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-P 451', 'INTEGRATIVE HUMAN PHYSIOLOGY', '4315', 'Class Status', 'F Friday 1:50 PM–3:50 PM', 'JH 122', 'Whitney Schlegel', 2, 'Laboratory', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intended for the junior or senior science major. Course in human physiology designed to introduce the senior undergraduate student to the function of the human body in health, disease, and extreme environments. Emphasizes how the different organ systems work to maintain homeostasis and how organ function is integrated. The content and key concepts are presented in order to provide students insight into the scientific process through problem-solving and exploration of resources. Utilizes experimental inquiry, case-based and problem-oriented methodology with students working in teams and an emphasis on clinical application. The laboratory component is incorporated into the structure of the course.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-P 451', 'INTEGRATIVE HUMAN PHYSIOLOGY', '10171', 'Class Status', 'F Friday 10:20 AM–12:20 PM', 'JH 122', 'Whitney Schlegel', 4, 'Laboratory', 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intended for the junior or senior science major. Course in human physiology designed to introduce the senior undergraduate student to the function of the human body in health, disease, and extreme environments. Emphasizes how the different organ systems work to maintain homeostasis and how organ function is integrated. The content and key concepts are presented in order to provide students insight into the scientific process through problem-solving and exploration of resources. Utilizes experimental inquiry, case-based and problem-oriented methodology with students working in teams and an emphasis on clinical application. The laboratory component is incorporated into the structure of the course.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-Q 201', 'BIOLOGICAL SCIENCE FOR ELEMENTARY TEACHERS', '1099', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'JH 065', 'Pamela Hanratty', 16, 'Lecture', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'An introduction to the principles and practice of biology designed especially for prospective elementary education teachers. All major areas of biology will be considered, with a concluding emphasis upon the relations between various organisms and their environment. Enrollment is limited to majors in elementary education.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-Q 201', 'BIOLOGICAL SCIENCE FOR ELEMENTARY TEACHERS', '1100', 'Class Status', 'Tu Tuesday 3:15 PM–6:15 PM', 'JH A104', 'Pamela Hanratty', 1, 'Laboratory', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'An introduction to the principles and practice of biology designed especially for prospective elementary education teachers. All major areas of biology will be considered, with a concluding emphasis upon the relations between various organisms and their environment. Enrollment is limited to majors in elementary education.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-Q 201', 'BIOLOGICAL SCIENCE FOR ELEMENTARY TEACHERS', '1101', 'Class Status', 'Tu Tuesday 6:45 PM–9:45 PM', 'JH A104', 'Pamela Hanratty', 15, 'Laboratory', 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'An introduction to the principles and practice of biology designed especially for prospective elementary education teachers. All major areas of biology will be considered, with a concluding emphasis upon the relations between various organisms and their environment. Enrollment is limited to majors in elementary education.', ARRAY['Class uses IU eTexts'], NULL),
    ('BIOL-S 211', 'MOLECULAR BIOLOGY, HONORS', '29769', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'JH A105', 'Xindan Wang', 0, 'Lecture', 'Lecture', '5', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Covers structure and function of DNA and RNA; DNA replication, mechanisms of mutation, repair, recombination, and transposition; mechanisms and regulation of gene expression; and the genetic code, transcription, and translation. Introduces bacteriophages, plasmids, and the technology of recombinant DNA. Course will be taught at an honors level.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('BIOL-S 211', 'MOLECULAR BIOLOGY, HONORS', '29770', 'Closed', 'F Friday 3:00 PM–6:00 PM', 'JH 015', 'Xindan Wang', 0, 'Laboratory', 'Lecture', '5', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Covers structure and function of DNA and RNA; DNA replication, mechanisms of mutation, repair, recombination, and transposition; mechanisms and regulation of gene expression; and the genetic code, transcription, and translation. Introduces bacteriophages, plasmids, and the technology of recombinant DNA. Course will be taught at an honors level.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('BIOL-S 311', 'GENETICS, HONORS', '10400', 'Closed', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'JH 440', 'Brian Calvi', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Trains students in the classic and modern principles of heredity and their application to understanding living systems and medicine. Requires rigorous engagement with the coursework, proficiency in independent scholarship, and regular participation in class discussions.', ARRAY[]::TEXT[], NULL),
    ('BIOL-T 583', 'PROBLEMS IN GENETICS - HIGHER ORGANISMS', '31684', 'Class Status', NULL, 'OL ONLINE', 'Jia Xue', 10, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Selected topics in the genetics of higher organisms emphasizing studies at the molecular level.', ARRAY[]::TEXT[], NULL),
    ('BIOL-X 150', 'ASURE BIOLOGY RESEARCH LAB 1', '10487', 'Class Status', 'F Friday 12:45 PM–1:35 PM', 'JH 001', 'Megan Murphy', 8, 'Discussion', 'Discussion', '4', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'First in a two-lab sequence for students in the Arts and Sciences Undergraduate Research Experience (ASURE) program. Students engage in guided research in an area related to the ongoing research of a faculty member. The specific topic of the class will vary by section and be determined by the faculty member associated with the section.', ARRAY[]::TEXT[], NULL),
