    ('BIOL-X 371', 'INTERNSHIP IN BIOLOGY INSTRUCTION', '7143', 'Class Status', NULL, NULL, 'Karen Whitworth, Sapna Mehta', 17, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'Supervised experience in teaching undergraduate biology course.', ARRAY[]::TEXT[], NULL),
    ('BIOL-X 371', 'INTERNSHIP IN BIOLOGY INSTRUCTION', '9135', 'Closed', NULL, NULL, 'Karen Whitworth, Sapna Mehta', 0, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'Supervised experience in teaching undergraduate biology course.', ARRAY[]::TEXT[], NULL),
    ('BIOL-X 473', 'INTERNSHIP IN BIOLOGY', '7521', 'Class Status', NULL, NULL, 'Whitney Schlegel', 25, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('BIOL-X 490', 'INDIVIDUAL STUDY', '7099', 'Class Status', NULL, NULL, 'Armin Moczek', 58, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Involves active, original research, primarily in a laboratory setting, with direction and feedback from a faculty mentor. Includes a formal presentation of the research project.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 375', 'INVERTEBRATE ZOOLOGY LAB', '1102', 'Class Status', 'Th Thursday 12:45 PM–5:10 PM', 'JH 122', 'Clara Cotten', 12, NULL, 'Laboratory', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Laboratory and field studies of invertebrates, with an emphasis on experiments with living specimens.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 460', 'ANIMAL BEHAVIOR', '5453', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'AC C002', 'Kimberly Rosvall', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 463', 'COMPARATIVE NEUROBIOLOGY OF ANIMAL BEHAVIOR', '29825', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LH 120', 'Gerald Smith', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Addresses the intersection of two disciplines: animal behavior and neurobiology. Uses integrative and comparative approaches to understand how the nervous system controls animal behavior in natural contexts and how neural circuits evolve to generate diversity in behavior.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 476', 'BIOLOGY OF FISHES', '29771', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'JH 440', 'Clara Cotten', 6, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Introduces diversity of extant fishes with respect to evolutionary relationships, classification, structure, function, behavior, ecology and biogeography.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 563', 'COMPARATIVE NEUROBIOLOGY OF ANIMAL BEHAVIOR', '29826', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'LH 120', 'Gerald Smith', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course addresses the intersection of two disciplines: animal behavior and neurobiology. The course uses integrative and comparative approaches to understand how the nervous system controls animal behavior in natural contexts and how neural circuits evolve to generate diversity in behavior.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 620', 'SPECIAL TOPICS IN ZOOLOGY', '4340', 'Class Status', 'Th Thursday 3:00 PM–6:00 PM', 'SI 001', 'Adam Zlotnick, Roger Innes', 12, NULL, 'Seminar', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Topics not extensively treated in other courses, e.g., theoretical zoology, oceanography, reservoir limnology, human ecology, biochemistry, viruses and disease, critical analysis of the scientific literature, and other fields. Topics presented will be repeated every three to five years.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 620', 'SPECIAL TOPICS IN ZOOLOGY', '9723', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'JH 001', 'Malcolm Winkler', 1, NULL, 'Seminar', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Topics not extensively treated in other courses, e.g., theoretical zoology, oceanography, reservoir limnology, human ecology, biochemistry, viruses and disease, critical analysis of the scientific literature, and other fields. Topics presented will be repeated every three to five years.', ARRAY[]::TEXT[], NULL),
