    ('BIOL-Z 620', 'SPECIAL TOPICS IN ZOOLOGY', '29877', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 142', 'Ankur Dalia', 14, NULL, 'Seminar', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Topics not extensively treated in other courses, e.g., theoretical zoology, oceanography, reservoir limnology, human ecology, biochemistry, viruses and disease, critical analysis of the scientific literature, and other fields. Topics presented will be repeated every three to five years.', ARRAY[]::TEXT[], NULL),
    ('BIOL-Z 620', 'SPECIAL TOPICS IN ZOOLOGY', '34503', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–11:00 AM', 'ED 1210', 'Ryan Bracewell', 7, NULL, 'Seminar', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Topics not extensively treated in other courses, e.g., theoretical zoology, oceanography, reservoir limnology, human ecology, biochemistry, viruses and disease, critical analysis of the scientific literature, and other fields. Topics presented will be repeated every three to five years.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 105', 'INTRODUCTION TO BIOTECHNOLOGY', '9404', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 1128', 'David Bollivar', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Provides insights into the science, methods, scope, diversity, history, business, and legal ramifications of biotechnology with the goal of demonstrating how different disciplines are integrated within the complex world of biotechnology. Examines biotechnological practices and activities, uses biotechnology to teach problem solving, and introduces existing impediments to progress in biotechnology.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('BIOT-T 301', 'SEMINAR IN BIOTECHNOLOGY', '5923', 'Class Status', 'Th Thursday 5:30 PM–7:30 PM', 'JH 001', 'David Bollivar', 2, NULL, 'Lecture', '1', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Speakers from the biotechnology industry and Walter Center for Career Achievement present current research developments, information about career opportunities, internship possibilities, and possible career paths in biotechnology.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 310', 'BIOTECHNOLOGY LECTURE', '5924', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'JH 009', 'Clay Fuqua', 18, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Application of microbial diversity in biotechnology; synthesis of macromolecules; principles of gene expressions; gene cloning; protein engineering, overexpression and purification; genomics; proteomics; bioinformatics.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 315', 'BIOTECHNOLOGY LABORATORY', '5925', 'Class Status', 'MW Monday, Wednesday 2:00 PM–5:00 PM', 'C2 118 BH 338', 'Nancy Magill', 2, NULL, 'Laboratory', '3', 'CLASSROOM-OFFICE BUILDING, BALLANTINE HALL', ARRAY[]::TEXT[], 'Students use a problem-based approach to gene cloning; for example, cloning the gene for an industrially important enzyme, a-amylase from Bacillus licheniformis. In this example, students would purify a-amylase from bacillus licheniformis and affinity-tagged a-amylase overproduction clone for purification and compare the activity of the purified proteins. Credit given for only one of BIOT-T315 or BIOL-T315.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 322', 'BIOTECHNOLOGY WRITING AND COMMUNICATION', '6286', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'BH 141', 'Nancy Magill', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Covers oral and written scientific communications as appropriate to biotechnology. Topics include figures and tables, scientific presentations, reading and writing scientific publications, and writing industrial-style documents, including standard operating procedures.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('BIOT-T 425', 'LABORATORY IN MACROMOLECULAR PRODUCTION, PURIFICATION, AND CHARACTERIZATION', '13585', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–3:45 PM', 'C2 118', 'Dan Held', 4, NULL, 'Laboratory', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Develops a working knowledge of a variety of fundamental and advanced protein techniques used in industry, focusing on expression, purification, and characterization. Increases competence in quantitative analysis, data interpretation, problem-solving, scientific writing, and time management.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 500', 'PROJECT LAB IN BIOTECHNOLOGY', '6012', 'Class Status', NULL, NULL, 'David Bollivar', 10, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Students explore different stages of scientific investigation by performing research using the techniques of biochemistry, molecular biology, genetics, and cell biology on problems related to biotechnology. Students design and execute research projects under supervision of the instructor in a teaching laboratory setting on problems chosen in consultation with the instructor.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 500', 'PROJECT LAB IN BIOTECHNOLOGY', '13132', 'Class Status', NULL, NULL, 'David Bollivar', 1, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Students explore different stages of scientific investigation by performing research using the techniques of biochemistry, molecular biology, genetics, and cell biology on problems related to biotechnology. Students design and execute research projects under supervision of the instructor in a teaching laboratory setting on problems chosen in consultation with the instructor.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 501', 'BIOCHEMISTRY INSTRUMENTATION', '10195', 'Class Status', 'W Wednesday 12:45 PM–1:35 PM', 'JH 248', 'David Bollivar', 7, 'Lecture', 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'This is a graduate level laboratory that is focused on biotechnology instrumentation used to characterize proteins. Students will learn theory as well as gain hands-on training in mass spectrometry, spectroscopic analysis of protein-ligand interactions, and capillary electrophoresis. Data generated will be used to develop lab reports.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 501', 'BIOCHEMISTRY INSTRUMENTATION', '10451', 'Class Status', 'MW Monday, Wednesday 9:00 AM–11:30 AM', 'JH 022', 'David Bollivar', 7, 'Laboratory', 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'This is a graduate level laboratory that is focused on biotechnology instrumentation used to characterize proteins. Students will learn theory as well as gain hands-on training in mass spectrometry, spectroscopic analysis of protein-ligand interactions, and capillary electrophoresis. Data generated will be used to develop lab reports.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 502', 'MAMMALIAN TISSUE CULTURE', '10196', 'Class Status', 'W Wednesday 12:45 PM–1:35 PM', 'JH 248', 'Mansi Srivastava', 5, 'Lecture', 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'This graduate level laboratory course that is designed to guide students through culturing and manipulations of different mammalian cell lines. Students will gain hands-on experience culturing cells, performing cell-based assays, and data interpretation.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 502', 'MAMMALIAN TISSUE CULTURE', '10452', 'Class Status', 'MW Monday, Wednesday 9:30 AM–12:00 PM', 'JH 022', 'Mansi Srivastava', 5, 'Laboratory', 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'This graduate level laboratory course that is designed to guide students through culturing and manipulations of different mammalian cell lines. Students will gain hands-on experience culturing cells, performing cell-based assays, and data interpretation.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 508', 'THEORY AND APPLICATIONS OF BIOTECHNOLOGY LECTURE I', '11154', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:45 AM', 'JH 248', 'Mansi Srivastava', 8, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Advanced graduate-level course focuses on the applications of molecular genetics and recombinant DNA in biotechnology. Fundamental concepts of relevant molecular biology and biochemistry will be covered in depth in the first portion of the class, followed by sections on recombinant DNA technology, macromolecular purification and genomics/bioinformatics.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 521', 'CONTEMPORARY TOPICS IN RESEARCH ETHICS', '10206', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'JH 440', 'Vera Edgeworth', 9, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'The course focuses on the responsible conduct of research pertaining to biochemistry and biotechnology, including topics related to current research ethics in both academic and industrial research.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 525', 'PROTEIN EXPRESSION, PURIFICATION, AND CHARACTERIZATION LABORATORY', '13586', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–3:45 PM', 'C2 118', 'Dan Held', 0, NULL, 'Laboratory', '3', 'CLASSROOM-OFFICE BUILDING', ARRAY[]::TEXT[], 'Students will develop fluency in the principles of protein expression, purification and characterization. They will develop capabilities in quantitative analysis of proteins, problem solving, data interpretation, critical thinking and time management. The course will focus on techniques and approaches commonly used in the biotechnology and pharmaceutical industries.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 590', 'GRADUATE RESEARCH', '8403', 'Class Status', NULL, NULL, 'David Bollivar', 20, NULL, 'Research', '1.5', NULL, ARRAY[]::TEXT[], 'Directed research opportunities for graduates in faculty research laboratories. Provides experience with state-of-the-art methodologies, instrumentation and approaches in biotechnology.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 590', 'GRADUATE RESEARCH', '8404', 'Class Status', NULL, NULL, 'David Bollivar', 20, NULL, 'Research', '1.5', NULL, ARRAY[]::TEXT[], 'Directed research opportunities for graduates in faculty research laboratories. Provides experience with state-of-the-art methodologies, instrumentation and approaches in biotechnology.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 590', 'GRADUATE RESEARCH', '6335', 'Class Status', NULL, NULL, 'David Bollivar', 19, NULL, 'Research', '1.5', NULL, ARRAY[]::TEXT[], 'Directed research opportunities for graduates in faculty research laboratories. Provides experience with state-of-the-art methodologies, instrumentation and approaches in biotechnology.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 590', 'GRADUATE RESEARCH', '11907', 'Class Status', NULL, NULL, 'David Bollivar', 5, NULL, 'Research', '1.5', NULL, ARRAY[]::TEXT[], 'Directed research opportunities for graduates in faculty research laboratories. Provides experience with state-of-the-art methodologies, instrumentation and approaches in biotechnology.', ARRAY[]::TEXT[], NULL),
    ('BIOT-T 680', 'SPECIALIZED TOPICS IN BIOTECHNOLOGY', '12659', 'Class Status', 'Th Thursday 5:30 PM–7:30 PM', 'JH 001', 'David Bollivar', 2, NULL, 'Lecture', '1', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'This is a specialized course covering a wide variety of topics of interest to graduate students pursuing a major or minor in Biotechnology. Instructors will comprise campus faculty with research interests in Biotechnology, but may also include visiting researchers from industries with experiential insights in the Biotechnology field.', ARRAY[]::TEXT[], NULL),
    ('BIOT-X 150', 'ASURE BIOTECHNOLOGY RESEARCH LAB 1', '13964', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–12:00 PM', 'JH 022', 'Ankur Dalia', 2, NULL, 'Laboratory', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'First in a two-lab sequence for students in the Arts and Sciences Undergraduate Research Experience (ASURE) program. Students engage in guided research in an area related to the ongoing research of a faculty member. The specific topic of the class will vary by section and be determined by the faculty member associated with the section.', ARRAY[]::TEXT[], NULL),
    ('BIOT-X 371', 'UNDERGRADUATE TEACHING INTERNSHIP IN BIOTECHNOLOGY', '7880', 'Class Status', NULL, NULL, 'Karen Whitworth, Sapna Mehta', 13, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Intern assists faculty in teaching an undergraduate course in Biotechnology: may hold discussion sections, develop handouts and lesson plans, but may not participate in grading. A final reflective essay about the experience is required.', ARRAY[]::TEXT[], NULL),
    ('BIOT-X 498', 'INDEPENDENT RESEARCH IN BIOTECHNOLOGY', '6334', 'Class Status', NULL, NULL, 'Armin Moczek', 11, NULL, 'Research', '1–3', NULL, ARRAY[]::TEXT[], 'Directed research opportunities for undergraduates in faculty research laboratories. Provides experience with state-of-the-art methodologies, instrumentation and approaches in biotechnology.', ARRAY[]::TEXT[], NULL),
    ('BIOT-X 499', 'BIOTECHNOLOGY RESEARCH CAPSTONE', '7881', 'Class Status', NULL, NULL, 'Armin Moczek', 13, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Student designs and performs an independent research project under the supervision of a faculty mentor. Requires a final written report on the research. If two semesters of X499 are completed and other departmental honors requirements are met, the written report may be used as an Honors thesis.', ARRAY[]::TEXT[], NULL),
    ('BUEX-F 500', 'FINANCIAL MANAGEMENT', '35561', 'Class Status', NULL, 'WB WEB', 'Russell Rhoads', 34, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course provides a working knowledge of the tools and analytical conventions used in the practice of corporate finance. The emphasis is on establishing an understanding of the basic elements of financial theory to be used in the application of analytical reasoning to business finance problems.', ARRAY['Class uses IU eTexts
Executive Degree Program Bloomington'], NULL),
    ('BUEX-F 516', 'ASSET PRICING AND SECURITY VALUATION', '35568', 'Class Status', NULL, 'WB WEB', 'Sridhar Arcot', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on valuation in capital markets by evaluating the risk and return of financial assets using quantitative methods. This includes topics in advanced portfolio theory, general asset pricing, bond pricing, and derivatives.', ARRAY['Class uses IU eTexts
Executive Degree Program Bloomington'], NULL),
    ('BUEX-F 547', 'SPECIAL TOPICS IN FINANCE', '35546', 'Class Status', NULL, 'WB WEB', 'Kristoph Kleiner', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Designed against the backdrop of the rapid growth of the use of technology in finance, this course teaches students to use machine learning techniques to predict outcomes in a variety of financial settings.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-K 521', 'QUANTITATIVE ANALYSIS', '35554', 'Class Status', NULL, 'WB WEB', 'John Hill', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In this course, we enhance the students basic statistical and mathematical modeling skills covering the following topics: probabilistic decision making, regression analysis, forecasting, simulation models, and optimization modeling with the EXCEL Solver. We also introduce how to solve similar problems using programming approaches.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-K 521', 'QUANTITATIVE ANALYSIS', '35555', 'Class Status', NULL, 'WB WEB', 'John Hill', 53, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In this course, we enhance the students basic statistical and mathematical modeling skills covering the following topics: probabilistic decision making, regression analysis, forecasting, simulation models, and optimization modeling with the EXCEL Solver. We also introduce how to solve similar problems using programming approaches.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-K 522', 'SIMULATION & OPTIMIZATION FOR BUSINESS ANALYTICS', '35547', 'Class Status', NULL, 'WB WEB', 'Aaron Perry', 9, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on building models for business situations using primarily optimization and simulation. The emphasis is on ehnancing decision making while gaining managerial insight. Topics include linear and non-linear models, finding solutions for combinatorial problems, simulation techniques to evaluate risk over a range of scenarios, and time series forecasting.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-M 555', 'INTEGRATED MARKETING STRATEGY', '35562', 'Closed', 'Tu Tuesday 7:30 PM–8:45 PM', 'WB WEB', 'Tony Stovall', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'You will learn how to create complete marketing strategies for individual products and product lines. You will learn how to drive lifetime customer value by anticipating changes in customer needs, creating multi-segment product/service offerings, creating new brands and leveraging existing ones, and creating multi-channel platforms.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-M 555', 'INTEGRATED MARKETING STRATEGY', '35563', 'Closed', 'Tu Tuesday 6:00 PM–7:15 PM', 'WB WEB', 'Tony Stovall', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'You will learn how to create complete marketing strategies for individual products and product lines. You will learn how to drive lifetime customer value by anticipating changes in customer needs, creating multi-segment product/service offerings, creating new brands and leveraging existing ones, and creating multi-channel platforms.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-M 555', 'INTEGRATED MARKETING STRATEGY', '35564', 'Closed', 'M Monday 7:30 PM–8:45 PM', 'WB WEB', 'Mark Mayer', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'You will learn how to create complete marketing strategies for individual products and product lines. You will learn how to drive lifetime customer value by anticipating changes in customer needs, creating multi-segment product/service offerings, creating new brands and leveraging existing ones, and creating multi-channel platforms.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-S 510', 'INFORMATION TECHNOLOGY PRINCIPLES', '35558', 'Class Status', NULL, 'WB WEB', 'Alexandre Barsi Lopes, Michael Collins', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'IT management roles and responsibilities, business applications, systems project management, end-user support, infrastructure management, enabling new organizational forms and learning.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-S 515', 'INFORMATION TECHNOLOGY', '35556', 'Closed', 'W Wednesday 6:00 PM–7:15 PM', 'WB WEB', 'Michael Frutiger', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'IT management roles and responsibilities, business applications, systems project management, end-user support, infrastructure management, enabling new organizational forms and learning.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-S 515', 'INFORMATION TECHNOLOGY', '35557', 'Closed', 'W Wednesday 7:30 PM–8:45 PM', 'WB WEB', 'Michael Frutiger', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'IT management roles and responsibilities, business applications, systems project management, end-user support, infrastructure management, enabling new organizational forms and learning.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-S 551', 'MACHINE LEARNING APPLICATIONS FOR BUSINESS', '35567', 'Class Status', NULL, 'WB WEB', 'David Darcy', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course helps students to effectively analyze data using machine learning approaches, enhance prediction performance and robustness, and extract valuable insights from large datasets to support managerial decision-making processes. The course structures machine learning knowledge into four layers: applications, tasks, models, and algorithms, applied to a variety of business contexts.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-S 553', 'DEEP LEARNING AND GENERATIVE AI FOR BUSINESS', '35552', 'Class Status', NULL, 'WB WEB', 'Sagar Samtani', 15, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers four modules providing overviews of: (1) prevailing application environments, modern data generating processes, data exploration approaches, and fundamental data encoding structures, (2) fundamental ML concepts, (3) DL and GenAI designs and learning strategy, implementation, and sample applications, and (4) DL and GenAI model evaluation, deployment, and presentation.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-V 594', 'EXPERIMENTAL COURSE FOR MBA IN MANAGEMENT: GLOBAL EXECUTIVE TRACK', '11807', 'Closed', NULL, 'WB WEB', 'Amanda Thacker, Fred Schlegel', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an experimental course offered to students in the new MBA in Management: Global Executive Track (MBAGET) Program.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-V 595', 'EXPERIMENTAL COURSE FOR MBA IN MANAGEMENT: GLOBAL EXECUTIVE TRACK', '10002', 'Closed', 'Non Standard Session', 'WB WEB', 'Amanda Thacker, Fred Schlegel', 0, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an experimental course offered to students in the new MBA in Management: Global Executive Track (MBAGET) Program.', ARRAY['Executive Degree Program Bloomington'], NULL),
