    ('BUEX-V 599', 'EXPERIMENTAL COURSE FOR MBA IN MANAGEMENT: GLOBAL EXECUTIVE TRACK', '34526', 'Closed', 'Six Week - First', 'WB WEB', 'Susan Batchelder', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an experimental course offered to students in the new MBA in Management: Global Executive Track (MBAGET) Program.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUEX-Z 513', 'RISK MANAGEMENT', '35550', 'Closed', 'Non Standard Session', 'WB WEB', 'Fred Schlegel, Amanda Thacker', 0, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course derives a comprehensive understanding of how derivative markets operate focuses on financial futures. It then covers how to identify financial risks and how to use derivatives within the context of risk management.', ARRAY['Executive Degree Program Bloomington'], NULL),
