    ('BUKD-F 750', 'FINANCIAL STRATEGY AND CORPORATE RESTRUCTURING', '35569', 'Class Status', NULL, 'WB WEB', 'Tod Perry, Jared Wilson', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course examines how corporate and financial strategies can lead to creation, maintenance, transfer, and destruction of shareholder value. Topics include valuing alternative strategies, effectively communicating strategies to financial markets, and aligning incentives of managers with shareholders. A framework for valuing mergers, acquisitions, and divestitures and other joint financing arrangements is developed and applied.', ARRAY['Class uses IU eTexts
Executive Degree Program Bloomington'], NULL),
    ('BUKD-F 755', 'FIXED-INCOME AND EQUITY ASSET VALUATION', '35119', 'Class Status', 'Tu Tuesday 6:00 PM–7:15 PM', 'WB WEB', 'Russell Rhoads', 16, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course introduces the tools of fixed-income and equity asset valuation. The format includes discussion forums, notes, CFA Institute Investment Series textbooks for both fixed-income and equity assets, example problems, assigned projects and exams.', ARRAY['Class uses IU eTexts
Kelley Direct Program Bloomington'], NULL),
    ('BUKD-G 528', 'PREDICTIVE ANALYTICS AND BUSINESS STRATEGY', '35565', 'Class Status', NULL, 'WB WEB', 'Ramses Armendariz Buaun', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The focus of this course will be on a subdivision of predictive analytics, called active prediction. Active prediction requires the use of causal inference, and some advanced causal inference tools are taught in this course. Students will develop communication skills regarding quantitative outputs.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUKD-G 561', 'MACROECONOMIC STRATEGIES FOR GLOBAL BUSINESS', '15019', 'Closed', 'M Monday 7:30 PM–8:45 PM', 'WB WEB', 'Andreas Hauskrecht', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Will develop skills to interpret the economic environment in which companies operate and identify the appropriate business response to macro shocks. We will analyze fiscal policy, monetary policy, economic growth, international trade and more to understand how they impact businesses. The course is not technical and focuses on applying theory.', ARRAY['Class uses IU eTexts
Executive Degree Program Bloomington'], NULL),
    ('BUKD-G 565', 'GAME THEORY AND STRATEGIC DECISION MAKING', '6650', 'Class Status', 'Tu Tuesday 6:00 PM–7:15 PM', 'WB WEB', 'Kerem Cakirer', 12, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'G565 delves deeper into the analysis of game theory and business strategy. The course is to strengthen your ability to think strategically in business situations, rather than to teach you facts or theories. We will iterate between theory and practice, utilizing interactive games, formal case studies, and real world examples.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-G 565', 'GAME THEORY AND STRATEGIC DECISION MAKING', '15015', 'Class Status', NULL, 'WB WEB', 'Kerem Cakirer', 17, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'G565 delves deeper into the analysis of game theory and business strategy. The course is to strengthen your ability to think strategically in business situations, rather than to teach you facts or theories. We will iterate between theory and practice, utilizing interactive games, formal case studies, and real world examples.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-G 565', 'GAME THEORY AND STRATEGIC DECISION MAKING', '7544', 'Closed', 'Tu Tuesday 7:30 PM–8:45 PM', 'WB WEB', 'Kerem Cakirer', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'G565 delves deeper into the analysis of game theory and business strategy. The course is to strengthen your ability to think strategically in business situations, rather than to teach you facts or theories. We will iterate between theory and practice, utilizing interactive games, formal case studies, and real world examples.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-G 596', 'ECONOMICS FOR MANAGERS', '9173', 'Closed', 'W Wednesday 6:00 PM–7:15 PM', 'WB WEB', 'Steven Kreft, Ellie Mafi-Kreft', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Managerial economics focuses on strategic decision making. For example, pricing strategy is based on the fundamental of price elasticity that is a cornerstone of the economic way of thinking, showing the optimal price will not only depend on price elasticity, but also cost considerations and the predicted reactions of competitors.', ARRAY['Kelley Direct Program Bloomington'], NULL),
