    ('BUKD-K 520', 'QUANTITATIVE ANALYSIS', '34081', 'Class Status', 'MW Monday, Wednesday 6:00 PM–7:30 PM', 'WB WEB', 'Aaron Perry', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on developing and building mathematical models that lead to good business solutions. Students will use probability, regression, optimization and simulation models to solve problems for a variety of business disciplines. The primary tool for constructing the models will be Excel, although the modeling skill is general.', ARRAY[]::TEXT[], NULL),
    ('BUKD-K 531', 'PREDICTIVE ANALYTICS AND DATA MINING', '5862', 'Closed', 'M Monday 7:30 PM–8:45 PM', 'WB WEB', 'Jay Newquist', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course on data mining focuses on the entire lifecycle of the predictive analytics process: 1) business understanding; 2) data understanding and preparation; 3) modeling; 4) evaluation; and 5) deployment. It focuses on data mining techniques for classification, numeric prediction, and association analysis.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUKD-K 533', 'ENTERPRISE DATA MANAGEMENT', '13002', 'Class Status', 'Th Thursday 7:30 PM–8:45 PM', 'WB WEB', 'Jie Li', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course covers concepts, processes, practices, tools used in the data life cycle. It teaches data model design, SQL, data quality control, data integration, data warehouse design, data visualization, data governance. Software: diagram tools (draw.io, etc.), MS SQL Server, SQL Management Studio, Talend for Data Quality, Alteryx, Tableau, etc.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-L 549', 'CRITICAL THINKING AND DECISION MAKING FOR EFFECTIVE LEADERSHIP', '10773', 'Class Status', 'Tu Tuesday 6:00 PM–7:15 PM', 'WB WEB', 'Stephanie Moore', 7, NULL, 'Discussion', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course is designed to improve students'' decision-making processes and thereby make them more effective leaders by providing them with a general framework for thinking critically, expanding on key aspects of that framework, and making students aware of systematic thinking shortcomings and providing them with knowledge / tools to counteract them.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-L 549', 'CRITICAL THINKING AND DECISION MAKING FOR EFFECTIVE LEADERSHIP', '34625', 'Class Status', 'Tu Tuesday 7:30 PM–8:45 PM', 'WB WEB', 'Stephanie Moore', 6, NULL, 'Discussion', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course is designed to improve students'' decision-making processes and thereby make them more effective leaders by providing them with a general framework for thinking critically, expanding on key aspects of that framework, and making students aware of systematic thinking shortcomings and providing them with knowledge / tools to counteract them.', ARRAY['Kelley Direct Program Bloomington'], NULL),
