    ('BUKD-M 501', 'CREATING WINNING DIGITAL MARKETING STRATEGIES', '15062', 'Class Status', 'M Monday 7:30 PM–8:45 PM', 'WB WEB', 'Brian Vander Schee', 16, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will develop your digital marketing skills needed to drive profitable growth and help you standout. You will learn how to effectively use email, search engines, social media, and digital advertising among other tools. The course is equally applicable to B2C companies.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-M 575', 'BUSINESS MARKETING STRATEGY', '11676', 'Class Status', 'W Wednesday 7:30 PM–8:45 PM', 'WB WEB', 'Joshua Gildea', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will help you create winning marketing strategies in a B2B context. You will learn practical frameworks related to value chain analysis, partnership management, organizational buyer behavior, segmentation and positioning, distribution channel design, product planning, value-based pricing, negotiation strategies, and integrated marketing communication planning.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-M 596', 'INTEGRATED MARKETING STRATEGY', '9719', 'Closed', 'Tu Tuesday 6:00 PM–7:15 PM', 'WB WEB', 'Girish Mallapragada', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'You will learn how to create complete marketing strategies for individual products and product lines. You will learn how to drive lifetime customer value by anticipating changes in customer needs, creating multi-segment product/service offerings, creating new brands and leveraging existing ones, and creating multi-channel platforms.', ARRAY['Kelley Direct Program Bloomington'], NULL),
