    ('BUKD-S 514', 'AI AND AUTOMATION IN BUSINESS', '36885', 'Class Status', 'Th Thursday 7:30 PM–8:45 PM', 'WB WEB', 'Alexandre Barsi Lopes, Michael Collins', 12, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Developing business capabilities for the digital future involves rethinking the current way of doing business in the context of understanding where the new frontiers of digital value may lie. To uncover the business capabilities, we will focus on Artificial Intelligence and its applications on the digital enterprise.', ARRAY[]::TEXT[], NULL),
    ('BUKD-S 596', 'DIGITAL TECHNOLOGY & INNOVATION', '9791', 'Closed', 'Th Thursday 6:00 PM–7:15 PM', 'WB WEB', 'Bipin Prabhakar', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This introduction to IT addresses skill and talent management; costs, budgets, value, and chargeback systems; priority setting and financial justification of investments; project management and runaway projects; in/outsourcing; security risks and crises; emerging technology approaches; communications with other senior executives; vendor management; infrastructure standardization; support for innovation; and risk management.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-S 596', 'DIGITAL TECHNOLOGY & INNOVATION', '9792', 'Closed', 'Th Thursday 7:30 PM–8:45 PM', 'WB WEB', 'Bipin Prabhakar', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This introduction to IT addresses skill and talent management; costs, budgets, value, and chargeback systems; priority setting and financial justification of investments; project management and runaway projects; in/outsourcing; security risks and crises; emerging technology approaches; communications with other senior executives; vendor management; infrastructure standardization; support for innovation; and risk management.', ARRAY['Kelley Direct Program Bloomington'], NULL),
