    ('BUKD-S 596', 'DIGITAL TECHNOLOGY & INNOVATION', '10720', 'Closed', 'W Wednesday 6:00 PM–7:15 PM', 'WB WEB', 'Brad Wheeler', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This introduction to IT addresses skill and talent management; costs, budgets, value, and chargeback systems; priority setting and financial justification of investments; project management and runaway projects; in/outsourcing; security risks and crises; emerging technology approaches; communications with other senior executives; vendor management; infrastructure standardization; support for innovation; and risk management.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-S 596', 'DIGITAL TECHNOLOGY & INNOVATION', '10721', 'Closed', 'W Wednesday 7:30 PM–8:45 PM', 'WB WEB', 'Brad Wheeler', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This introduction to IT addresses skill and talent management; costs, budgets, value, and chargeback systems; priority setting and financial justification of investments; project management and runaway projects; in/outsourcing; security risks and crises; emerging technology approaches; communications with other senior executives; vendor management; infrastructure standardization; support for innovation; and risk management.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-S 596', 'DIGITAL TECHNOLOGY & INNOVATION', '10722', 'Closed', 'W Wednesday 9:00 PM–10:15 PM', 'WB WEB', 'Brad Wheeler', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This introduction to IT addresses skill and talent management; costs, budgets, value, and chargeback systems; priority setting and financial justification of investments; project management and runaway projects; in/outsourcing; security risks and crises; emerging technology approaches; communications with other senior executives; vendor management; infrastructure standardization; support for innovation; and risk management.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-U 702', 'ORGANIZATIONAL BEHAVIOR AND DECISION MAKING', '14890', 'Closed', 'W Wednesday 6:00 PM–7:15 PM', 'WB WEB', 'Julie Kratz', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is an introduction to the basic concepts/topics in strategic leadership/decision making. Covers several topics that are related to managing/leading people in organizations, including: personality, decision making, motivation, leadership, team dynamics, negotiations, organizational culture. Examines how individuals in organizations function across different contexts/levels of analysis: individually, interpersonally in groups/organizations.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUKD-U 710', 'STRATEGIC MANAGEMENT AND LEADERSHIP', '9816', 'Closed', 'W Wednesday 9:00 PM–10:15 PM', 'WB WEB', 'James Davis', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The primary focus of this course is the top-level executives who provide strategic leadership to business organizations. Students will learn about the roles, functions, and responsibilities of leadership, in order to learn administrative requirements of leadership. In addition, students will be introduced to the analytical skills and social and person characteristics of highly effective leaders. Case students, videotapes, and other media will be used to explore these and related issues.', ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUKD-W 524', 'STRATEGIC ENTREPRENEURSHIP', '34633', 'Class Status', 'M Monday 6:00 PM–7:15 PM', 'WB WEB', 'Greg Fisher', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Class builds on core strategy content and integrates it with other entrepreneurship, innovation, and management concepts to explore new venture creation, growth, and strategic decision-making under uncertainty. Focuses on strategic issues involved in creating a new venture, rapidly scaling a product or service, or acquiring, developing, and growing existing business.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-W 524', 'STRATEGIC ENTREPRENEURSHIP', '34634', 'Class Status', 'M Monday 7:30 PM–8:45 PM', 'WB WEB', 'Greg Fisher', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Class builds on core strategy content and integrates it with other entrepreneurship, innovation, and management concepts to explore new venture creation, growth, and strategic decision-making under uncertainty. Focuses on strategic issues involved in creating a new venture, rapidly scaling a product or service, or acquiring, developing, and growing existing business.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-W 524', 'STRATEGIC ENTREPRENEURSHIP', '34635', 'Class Status', 'M Monday 9:00 PM–10:15 PM', 'WB WEB', 'Greg Fisher', 7, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Class builds on core strategy content and integrates it with other entrepreneurship, innovation, and management concepts to explore new venture creation, growth, and strategic decision-making under uncertainty. Focuses on strategic issues involved in creating a new venture, rapidly scaling a product or service, or acquiring, developing, and growing existing business.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-W 568', 'THE SILICON VALLEY VENTURE CHALLENGE', '8670', 'Closed', 'M Monday 6:00 PM–7:15 PM', 'WB WEB', 'Donald Kuratko', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In order to immerse students into the startup world of Silicon Valley, this specially designed graduate course prepares students to "pitch" a business plan to experts in Silicon Valley. This course is designed for students to examine and understand the successful development of a new venture.', ARRAY['Kelley Direct Program Bloomington'], NULL),
