    ('BUKD-X 532', 'TOPICS IN BUSINESS CAPSTONE', '6008', 'Closed', 'W Wednesday 6:30 PM–7:45 PM', 'WB WEB', 'Richard Magjuka', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY['Executive Degree Program Bloomington'], NULL),
    ('BUKD-X 572', 'EXPERIMENTAL COURSE FOR MBA PROGRAM', '15191', 'Closed', 'Tu Tuesday 7:30 PM–8:45 PM', 'WB WEB', 'Wendy Pottgen', 0, NULL, 'Lecture', '1.5', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An experimental course to be used and assigned by the MBA Office to specific departments in the School of Business on a one-time basis until and if a permanent number in a department is assigned.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-X 596', 'INTEGRATED CAPSTONE COURSE', '9794', 'Closed', NULL, 'WB WEB', 'Greg Fisher', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In this live case course, we will integrate in a capstone manner the main classes you have taken thus far in your MBA core to perform an integrative analysis of a publicly traded company with the goal of developing integrative and cross functional recommendations.', ARRAY['Kelley Direct Program Bloomington'], NULL),
