    ('BUKD-X 596', 'INTEGRATED CAPSTONE COURSE', '10777', 'Closed', NULL, 'WB WEB', 'Greg Fisher', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In this live case course, we will integrate in a capstone manner the main classes you have taken thus far in your MBA core to perform an integrative analysis of a publicly traded company with the goal of developing integrative and cross functional recommendations.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-X 596', 'INTEGRATED CAPSTONE COURSE', '10778', 'Closed', NULL, 'WB WEB', 'Greg Fisher', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In this live case course, we will integrate in a capstone manner the main classes you have taken thus far in your MBA core to perform an integrative analysis of a publicly traded company with the goal of developing integrative and cross functional recommendations.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-Z 511', 'MANAGING CHANGE IN ORGANIZATIONS', '34569', 'Class Status', 'W Wednesday 9:00 PM–10:15 PM', 'WB WEB', 'Markus Vodosek', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on the key principles, practices, and processes of leading organizational change. After taking this course, students will be able to successfully apply evidence-based frameworks and tools to bring about planned change in organizations.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-Z 512', 'LEADERSHIP, TEAMS AND INCLUSION', '10770', 'Class Status', 'M Monday 6:00 PM–7:15 PM', 'WB WEB', 'Raymond Luther, Erik Gonzalez-Mule', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will cover the science of effective team leadership. It focuses on the drivers of team effectiveness, including team cognition, motivation, and attitudes, selection, and design. The course also explores the critical role of inclusion to ensure that individuals feel recognized for their contributions to the organization''s success.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-Z 512', 'LEADERSHIP, TEAMS AND INCLUSION', '10771', 'Class Status', 'M Monday 7:30 PM–8:45 PM', 'WB WEB', 'Raymond Luther, Erik Gonzalez-Mule', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will cover the science of effective team leadership. It focuses on the drivers of team effectiveness, including team cognition, motivation, and attitudes, selection, and design. The course also explores the critical role of inclusion to ensure that individuals feel recognized for their contributions to the organization''s success.', ARRAY['Kelley Direct Program Bloomington'], NULL),
    ('BUKD-Z 596', 'LEADING ORGANIZATION', '9182', 'Closed', 'Tu Tuesday 6:00 PM–7:15 PM', 'WB WEB', 'Ernest O''Boyle, Chelsea Song', 0, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'All organizations are comprised of three types of resources: financial and material capital, intellectual property, and people. Many contemporary organizations are finding that the people they employ - and the knowledge and expertise these people hold - are their best source of competitive advantage.', ARRAY['Kelley Direct Program Bloomington'], NULL),
