    ('BUS-A 307', 'FINANCIAL REPORTING AND ANALYSIS: HONORS', '10243', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 2050', 'John Wertz', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A307 will teach students about financial reporting of accounting information about firms for decision-making by external stakeholders, including investors, creditors, and others. A307 will be organized with 5 major themes: a. Supply of and Demand for Financial Accounting Information; b. Record-Keeping; c. Measurement; d. Reporting; e. Analysis and Decision-Making', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 307', 'FINANCIAL REPORTING AND ANALYSIS: HONORS', '10244', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 2050', 'John Wertz', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A307 will teach students about financial reporting of accounting information about firms for decision-making by external stakeholders, including investors, creditors, and others. A307 will be organized with 5 major themes: a. Supply of and Demand for Financial Accounting Information; b. Record-Keeping; c. Measurement; d. Reporting; e. Analysis and Decision-Making', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 307', 'FINANCIAL REPORTING AND ANALYSIS: HONORS', '10432', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 2050', 'John Wertz', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A307 will teach students about financial reporting of accounting information about firms for decision-making by external stakeholders, including investors, creditors, and others. A307 will be organized with 5 major themes: a. Supply of and Demand for Financial Accounting Information; b. Record-Keeping; c. Measurement; d. Reporting; e. Analysis and Decision-Making', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 310', 'INTERMEDIATE FINANCIAL REPORTING AND ANALYSIS: A USER''S PERSPECTIVE', '1111', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 3030', 'David Volant', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An exploration of financial accounting topics with the emphasis on analysis and interpretation rather than on the detailed mechanics and procedures of accounting. It provides understanding of how financial statements reflect management decisions in the activity areas of financing, investing, and operating.', ARRAY['Class uses IU eTexts'], NULL),
