    ('BUS-A 315', 'ASSURANCE AND RISK ADVISORY WORKSHOP', '11088', 'Closed', 'Tu Tuesday 6:30 PM–7:45 PM', 'HH 1030', 'Lori Bhaskar', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Introduces students to career opportunities in assurance services, risk management, and control systems.', ARRAY[]::TEXT[], NULL),
