    ('BUS-A 324', 'MANAGEMENT ACCOUNTING FOR FINANCE PROFESSIONALS', '4473', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 3034', 'Tom Lunsford', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides an application-based approach to common financial planning, decision making, and evaluation tasks undertaken by finance professionals. Using a management accounting framework, students will enhance their ability to identify and assess relevant costs and revenues necessary for making data-driven decisions that are common to businesses and operating units.', ARRAY['Class uses IU eTexts'], NULL),
