    ('BUS-A 329', 'TAXES AND DECISION MAKING', '29363', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 3006', 'Fred Coleman', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The course provides a broad understanding of the federal income tax consequences of common business and investment transactions. Students will learn the role of income taxes in evaluating individual taxpayer and business decisions, apply federal income tax laws appropriately, and differentiate financial reporting standards from federal tax law.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 333', 'TAXES AND FINANCIAL PLANNING FOR INDIVIDUALS', '14077', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 1038', 'Greg Geisler', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the federal income taxation of individuals and how to use the tax laws to engage in tax planning strategies that maximize wealth.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 337', 'ACCOUNTING INFORMATION SYSTEMS', '4986', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 4006', 'Joshua Dennis', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course takes integrative approach to showcase how accounting applications are at core of every organization''s enterprise systems and includes topics such as systems selection/architecture, role of IT in an organization, business cycles (e.g., Purchase-to-pay, Order-to-cash), internal controls, process mapping, project management and hands-on use of enterprise systems software.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 337', 'ACCOUNTING INFORMATION SYSTEMS', '4987', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'HH 4006', 'Joshua Dennis', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course takes integrative approach to showcase how accounting applications are at core of every organization''s enterprise systems and includes topics such as systems selection/architecture, role of IT in an organization, business cycles (e.g., Purchase-to-pay, Order-to-cash), internal controls, process mapping, project management and hands-on use of enterprise systems software.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 337', 'ACCOUNTING INFORMATION SYSTEMS', '4988', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 4006', 'Joshua Dennis', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course takes integrative approach to showcase how accounting applications are at core of every organization''s enterprise systems and includes topics such as systems selection/architecture, role of IT in an organization, business cycles (e.g., Purchase-to-pay, Order-to-cash), internal controls, process mapping, project management and hands-on use of enterprise systems software.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 337', 'ACCOUNTING INFORMATION SYSTEMS', '6727', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4006', 'Joshua Dennis', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course takes integrative approach to showcase how accounting applications are at core of every organization''s enterprise systems and includes topics such as systems selection/architecture, role of IT in an organization, business cycles (e.g., Purchase-to-pay, Order-to-cash), internal controls, process mapping, project management and hands-on use of enterprise systems software.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 355', 'TOPICS IN ACCOUNTING', '12377', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3034', 'Katie Metz', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Accounting.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 355', 'TOPICS IN ACCOUNTING', '29964', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3034', 'Katie Metz', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Accounting.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 420', 'FINANCIAL STATEMENT ANALYSIS AND INTERPRETATION', '32780', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 2046', 'Jerry Mathis', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Learn to use corporate financial statements and their accompanying disclosures in making business decisions. A comprehensive analytical framework provides tools to analyze and interpret financial statement information. We integrate concepts from accounting, finance, economics, and strategy to understand the business context of financial statement analyses and their purpose.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 422', 'ACCOUNTING FOR MERGERS, ACQUISITIONS, AND COMPLEX FINANCIAL STRUCTURES', '7838', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 3034', 'P.J. Hoffman', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines accounting for intercompany investments, consolidated financial statements, and other complex arrangements. Topics include mergers and acquisitions, spin-offs and split-offs, foreign currency transactions, derivatives, and other topics.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 422', 'ACCOUNTING FOR MERGERS, ACQUISITIONS, AND COMPLEX FINANCIAL STRUCTURES', '29968', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 3034', 'P.J. Hoffman', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines accounting for intercompany investments, consolidated financial statements, and other complex arrangements. Topics include mergers and acquisitions, spin-offs and split-offs, foreign currency transactions, derivatives, and other topics.', ARRAY[]::TEXT[], NULL),
    ('BUS-A 424', 'FOUNDATIONS OF AUDITING', '4262', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 2050', 'Lori Bhaskar', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A424 focuses on the concepts, standards, and procedures of financial statement auditing, as well as the role of auditing in society. It focuses on the audit process related to risk assessments, internal controls, audit evidence, and auditor reporting. It also develops critical thinking skills by focusing on auditors'' professional judgments', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 424', 'FOUNDATIONS OF AUDITING', '12050', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 2050', 'Lori Bhaskar', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A424 focuses on the concepts, standards, and procedures of financial statement auditing, as well as the role of auditing in society. It focuses on the audit process related to risk assessments, internal controls, audit evidence, and auditor reporting. It also develops critical thinking skills by focusing on auditors'' professional judgments', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 424', 'FOUNDATIONS OF AUDITING', '29969', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 2050', 'Lori Bhaskar', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A424 focuses on the concepts, standards, and procedures of financial statement auditing, as well as the role of auditing in society. It focuses on the audit process related to risk assessments, internal controls, audit evidence, and auditor reporting. It also develops critical thinking skills by focusing on auditors'' professional judgments', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 437', 'ADVANCED MANAGEMENT ACCOUNTING FOR DECISION MAKING AND CONTROL: THEORY AND APPLICATIONS', '12234', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 3030', 'Geoffrey Sprinkle', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Via opportunity costs and organizational architecture, A437 provides students with an inclusive framework for understanding the integral decision making and control roles of management accounting in organizations. The course focuses particularly on the theoretical and conceptual underpinnings of managerial accounting systems and uses numerous contextually-rich problems and cases', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-A 506', 'FINANCIAL REPORTING AND ANALYSIS I', '12865', 'Class Status', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 1026', 'P.J. Hoffman', 9, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course examines how financial statements are prepared and how financial statement information is useful for financial decisions - from the distinct perspective of financial statement users. Topics include generally accepted accounting principles, the accounting cycle, accounting measurements, and the information reported in financial statements and their footnotes.', ARRAY['Class uses IU eTexts'], NULL)
